.wrapper {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  box-sizing: border-box;
  container-type: inline-size;
  height: 100%;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
  font-variant-numeric: tabular-nums;
}

/* Chart card -- calm dark surface, hairline border, resting depth shadow (Helios Dark chart-card recipe). */
.wrapper .brc-card {
  position: relative;
  display: flex;
  flex-direction: column;
  box-sizing: border-box;
  min-width: 0;
  height: 100%;
  min-height: 280px;
  background: var(--surface);
  border: 1px solid var(--line);
  border-radius: 14px;
  padding: 16px 18px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  transition: border-color .15s ease, box-shadow .15s ease;
}
/* Live card (refreshes with the page filters) -- restrained border-brighten toward the accent on hover. */
/* No glow: per the design system glow is reserved for hero/active/selected; a chart card stays calm. */
.wrapper .brc-card:hover {
  border-color: color-mix(in srgb, var(--accent) 35%, var(--line));
}

/* Header -- yellow accent dot + card title, muted caption sub. Airy 4px rhythm. */
.wrapper .brc-head {
  display: flex;
  flex-direction: column;
  gap: 4px;
  margin: 0 0 12px;
  min-width: 0;
}
.wrapper .brc-title {
  display: flex;
  align-items: center;
  gap: 8px;
  margin: 0;
  min-width: 0;
  overflow-wrap: anywhere;
  font: 800 14px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -0.01em;
  color: var(--ink);
}
.wrapper .brc-title::before {
  content: "";
  flex: 0 0 auto;
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--accent);
}
.wrapper .brc-sub {
  margin: 0;
  overflow-wrap: anywhere;
  font: 600 11px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--muted);
}

/* Plot box -- fills the card, keeps a height floor so the chart never collapses. */
/* Chart series/axis colors live in the ECharts options (JS) and already follow the dark recipe. */
.wrapper .brc-canvas {
  flex: 1 1 auto;
  width: 100%;
  min-width: 0;
  max-width: 100%;
  min-height: 240px;
}

/* Empty-selection state -- no spinner / no loading copy; Portal renders the skeleton loader. */
.wrapper .brc-empty {
  flex: 1 1 auto;
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 240px;
  margin: 0;
  padding: 16px;
  text-align: center;
  color: var(--muted);
  font: 600 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}
.wrapper .brc-empty[hidden] { display: none; }

/* Accent focus ring for any focusable element inside the block. */
.wrapper :focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
}

@media (prefers-reduced-motion: reduce) {
  .wrapper .brc-card { transition: none; }
}

/* ---- Responsive (design.md section 9): collapse on the block's OWN cell width via container queries. ---- */
/* .wrapper is container-type:inline-size, so these query the block's grid cell, not the viewport. */
/* This block is one half of a chart pair: when its cell narrows past the 720px stack point it keeps */
/* the canvas min-height:220px floor so the chart never collapses to zero height when stacked. */
@container (max-width: 720px) {
  .wrapper .brc-card { padding: 14px; }
  .wrapper .brc-canvas,
  .wrapper .brc-empty { min-height: 220px; }
}
@container (max-width: 480px) {
  .wrapper .brc-card { min-height: 260px; padding: 12px; border-radius: 12px; }
  .wrapper .brc-head { margin: 0 0 10px; }
  .wrapper .brc-title { font-size: 13px; }
  .wrapper .brc-sub { font-size: 10.5px; }
  .wrapper .brc-canvas,
  .wrapper .brc-empty { min-height: 220px; }
}

/* Viewport fallback for engines without container-query support (the block's cell is usually */
/* near the viewport width at these sizes); mirrors the chart-pair stack floor above. */
@supports not (container-type: inline-size) {
  @media (max-width: 720px) {
    .wrapper .brc-card { padding: 14px; }
    .wrapper .brc-canvas,
    .wrapper .brc-empty { min-height: 220px; }
  }
}
